function s(){document.querySelectorAll("form").forEach(r=>{r.dataset.loaderInitialized||(r.addEventListener("submit",function(){const t=this.querySelector('[type="submit"]');if(!t)return;const o=t.querySelector(".btn-text"),n=t.querySelector(".btn-loader");if(o&&n)try{Array.from(t.children).forEach(e=>{e.classList.contains("btn-loader")||(e.style.display="none")}),n.style.display="flex",t.disabled=!0}catch(e){console.warn("Button loader failed:",e)}else t.disabled=!0,t.textContent="Memproses..."}),r.dataset.loaderInitialized="true")})}export{s as initButtonLoader};
